      SELECT 100000 COD, 'NAO INFORMADO O WEBSERVICE PARA UF DO EMITENTE NO CONFIGURADOR' DESCRICAO FROM DUAL UNION
      SELECT 100001 COD, 'PROBLEMA COM CERTIFICADO DIGITAL' DESCRICAO FROM DUAL UNION
      SELECT 100002 COD, 'ERRO NA CHAMADA DO WEBSERVICE' DESCRICAO FROM DUAL UNION
      SELECT 100003 COD, 'CONSUMO DE UM WEBSERVICE UTILIZANDO O WSDL DE OUTRO' DESCRICAO FROM DUAL UNION
      SELECT 100004 COD, 'PERMITIR CANCELAMENTO DE NOTAS DA ABA PENDENTES' DESCRICAO FROM DUAL 
            
  ) LOOP
  
  SELECT COUNT(*) INTO ICOUNT FROM PCMENSAGEMNFE WHERE CODMENSAGEM = DADOS.COD;
  
  IF ICOUNT = 0 THEN
     INSERT INTO PCMENSAGEMNFE (CODMENSAGEM, DESCRICAO) VALUES(DADOS.COD ,DADOS.DESCRICAO);
  ELSE
     UPDATE PCMENSAGEMNFE SET
     DESCRICAO = DADOS.DESCRICAO
     WHERE CODMENSAGEM = DADOS.COD;       
  END IF;
  END LOOP;
  COMMIT;
END;

